    public string Decrypt(string encryptedCreditCardNumber)
    {
        if (string.IsNullOrEmpty(encryptedCreditCardNumber))
        {
            throw new ArgumentNullException(nameof(encryptedCreditCardNumber));
        }

        string[] parts = encryptedCreditCardNumber.Split(':');
        byte[] iv = Convert.FromBase64String(parts[0]);
        byte[] encryptedBytes = Convert.FromBase64String(parts[1]);

        using (Aes aes = Aes.Create())
        {
            aes.Key = _key;
            aes.IV = iv;
            ICryptoTransform decryptor = aes.CreateDecryptor(aes.Key, aes.IV);
            try
